
#ifndef BCMAGIC_INCLUDED__
#define BCMAGIC_INCLUDED__

#include "Exports.h"

///////////////////////////////////////////////////////////////////////////////
// Namespace : BC
///////////////////////////////////////////////////////////////////////////////

BC_NAMESPACE_BEGINDECLS(BC);

///////////////////////////////////////////////////////////////////////////////
// struct : BCMagic
///////////////////////////////////////////////////////////////////////////////

struct BC_API BCMagic
{
	BCMagic(uint32_t nMagic)
	{
		m_nMagic = nMagic;
	}
	virtual ~BCMagic()
	{
		m_nMagic = 0;
	}

	uint32_t		m_nMagic;
};

/*%
 * To use this macro the magic number MUST be the first thing in the
 * structure, and MUST be of type "unsigned int".
 * The intent of this is to allow magic numbers to be checked even though
 * the object is otherwise opaque.
 */
#define BC_MAGIC_VALID(a,b)	(((a) != NULL) && \
				 ((a)->m_nMagic == (b)))

#define BC_MAGIC(a, b, c, d)	((a) << 24 | (b) << 16 | (c) << 8 | (d))

///////////////////////////////////////////////////////////////////////////////
// End of namespace :
///////////////////////////////////////////////////////////////////////////////

BC_NAMESPACE_ENDDECLS(BC);

#endif

